mapper.insert:
INSERT INTO event.payment_intents (
     pg_provider
    ,pg_mid
    ,pg_order_id
    ,amount
    ,currency
    ,payment_method
    ,status
    ,raw_response
    ,event_seq
    ,event_pricing_seq
    ,original_amount
    ,discount_amount
    ,refunded_amount
    ,payer_name
    ,payer_email
    ,payer_country
    ,first_name
    ,middle_name
    ,last_name
    ,organization_name
    ,position
    ,created_by
    ,updated_by
) VALUES (
     #{pgProvider}
    ,#{pgMid}
    ,#{pgOrderId}
    ,#{amount}
    ,#{currency}
    ,#{paymentMethod}
    ,#{status}
    ,CAST(#{rawResponse,jdbcType=VARCHAR} AS JSONB)
    ,#{eventSeq}
    ,#{eventPricingSeq}
    ,#{originalAmount}
    ,COALESCE(#{discountAmount,jdbcType=NUMERIC}, 0)
    ,COALESCE(#{refundedAmount,jdbcType=NUMERIC}, 0)
    ,#{payerName}
    ,#{payerEmail}
    ,#{payerCountry,jdbcType=VARCHAR}
    ,#{firstName}
    ,NULLIF(#{middleName,jdbcType=VARCHAR}, '')
    ,#{lastName}
    ,NULLIF(#{organizationName,jdbcType=VARCHAR}, '')
    ,NULLIF(#{position,jdbcType=VARCHAR}, '')
    ,#{createdBy}
    ,#{updatedBy}
)

mapper.update:
UPDATE event.payment_intents
SET  status        = #{status}
    ,failed_reason = #{failedReason,jdbcType=VARCHAR}
    ,raw_response  = CAST(#{rawResponse,jdbcType=VARCHAR} AS JSONB)
    ,completed_at  = #{completedAt,jdbcType=TIMESTAMP}
    ,payment_seq   = #{paymentSeq,jdbcType=BIGINT}
    ,updated_by    = #{updatedBy,jdbcType=BIGINT}
    ,updated_at    = now()
WHERE payment_intent_seq = #{paymentIntentSeq}

mapper.insert:
INSERT INTO event.payments (
     pg_provider
    ,pg_mid
    ,pg_order_id
    ,pg_transaction_id
    ,amount
    ,currency
    ,payment_method
    ,card_company
    ,card_last4
    ,status
    ,paid_at
    ,failed_reason
    ,receipt_url
    ,raw_response
    ,pg_response_code
    ,pg_response_message
    ,verified_at
    ,webhook_received_at
    ,event_seq
    ,event_participant_seq
    ,participant_seq
    ,payer_name
    ,payer_email
    ,payer_country
    ,settle_amount
    ,settle_currency
    ,fx_rate
    ,approval_no
    ,installment_months
    ,event_pricing_seq
    ,original_amount
    ,discount_code_seq
    ,discount_amount
    ,refunded_amount
    ,created_by
    ,updated_by
) VALUES (
     #{pgProvider}
    ,#{pgMid}
    ,#{pgOrderId}
    ,#{pgTransactionId,jdbcType=VARCHAR}
    ,#{amount}
    ,#{currency}
    ,#{paymentMethod}
    ,#{cardCompany,jdbcType=VARCHAR}
    ,#{cardLast4,jdbcType=VARCHAR}
    ,#{status}
    ,#{paidAt,jdbcType=TIMESTAMP}
    ,#{failedReason,jdbcType=VARCHAR}
    ,#{receiptUrl,jdbcType=VARCHAR}
    ,CAST(#{rawResponse,jdbcType=VARCHAR} AS JSONB)
    ,#{pgResponseCode,jdbcType=VARCHAR}
    ,#{pgResponseMessage,jdbcType=VARCHAR}
    ,#{verifiedAt,jdbcType=TIMESTAMP}
    ,COALESCE(#{webhookReceivedAt,jdbcType=TIMESTAMP}, now())
    ,#{eventSeq}
    ,#{eventParticipantSeq}
    ,#{participantSeq}
    ,#{payerName}
    ,#{payerEmail}
    ,#{payerCountry,jdbcType=VARCHAR}
    ,#{settleAmount,jdbcType=NUMERIC}
    ,#{settleCurrency,jdbcType=VARCHAR}
    ,#{fxRate,jdbcType=NUMERIC}
    ,#{approvalNo,jdbcType=VARCHAR}
    ,#{installmentMonths,jdbcType=INTEGER}
    ,#{eventPricingSeq}
    ,#{originalAmount}
    ,#{discountCodeSeq,jdbcType=BIGINT}
    ,COALESCE(#{discountAmount,jdbcType=NUMERIC}, 0)
    ,COALESCE(#{refundedAmount,jdbcType=NUMERIC}, 0)
    ,#{createdBy}
    ,#{updatedBy}
)

mapper.update:
UPDATE event.payments
SET  pg_provider            = #{pgProvider}
    ,pg_mid                 = #{pgMid}
    ,pg_order_id            = #{pgOrderId}
    ,pg_transaction_id      = NULL
    ,amount                 = #{amount}
    ,currency               = #{currency}
    ,payment_method         = #{paymentMethod}
    ,card_company           = NULL
    ,card_last4             = NULL
    ,status                 = 'pending'
    ,paid_at                = NULL
    ,failed_reason          = NULL
    ,receipt_url            = NULL
    ,raw_response           = CAST(#{rawResponse,jdbcType=VARCHAR} AS JSONB)
    ,pg_response_code       = NULL
    ,pg_response_message    = NULL
    ,verified_at            = NULL
    ,webhook_received_at    = NULL
    ,settle_amount          = NULL
    ,settle_currency        = NULL
    ,fx_rate                = NULL
    ,approval_no            = NULL
    ,installment_months     = NULL
    ,event_seq              = #{eventSeq}
    ,event_participant_seq  = #{eventParticipantSeq}
    ,participant_seq        = #{participantSeq}
    ,payer_name             = #{payerName}
    ,payer_email            = #{payerEmail}
    ,payer_country          = #{payerCountry,jdbcType=VARCHAR}
    ,event_pricing_seq      = #{eventPricingSeq}
    ,original_amount        = #{originalAmount}
    ,discount_code_seq      = #{discountCodeSeq,jdbcType=BIGINT}
    ,discount_amount        = COALESCE(#{discountAmount,jdbcType=NUMERIC}, 0)
    ,refunded_amount        = COALESCE(#{refundedAmount,jdbcType=NUMERIC}, 0)
    ,cancelled_at           = NULL
    ,cancel_reason          = NULL
    ,updated_by             = #{updatedBy,jdbcType=BIGINT}
    ,updated_at             = now()
WHERE payment_seq = #{paymentSeq}

UPDATE event.payments
SET  pg_provider            = #{pgProvider}
    ,pg_mid                 = #{pgMid}
    ,pg_order_id            = #{pgOrderId}
    ,pg_transaction_id      = COALESCE(NULLIF(#{pgTransactionId,jdbcType=VARCHAR}, ''), pg_transaction_id)
    ,amount                 = COALESCE(#{amount,jdbcType=NUMERIC}, amount)
    ,currency               = COALESCE(NULLIF(#{currency,jdbcType=VARCHAR}, ''), currency)
    ,payment_method         = COALESCE(NULLIF(#{paymentMethod,jdbcType=VARCHAR}, ''), payment_method)
    ,card_company           = NULLIF(#{cardCompany,jdbcType=VARCHAR}, '')
    ,card_last4             = NULLIF(#{cardLast4,jdbcType=VARCHAR}, '')
    ,status                 = #{status}
    ,paid_at                = CASE WHEN #{paidAt,jdbcType=TIMESTAMP} IS NULL THEN paid_at ELSE #{paidAt,jdbcType=TIMESTAMP} END
    ,failed_reason          = #{failedReason,jdbcType=VARCHAR}
    ,receipt_url            = #{receiptUrl,jdbcType=VARCHAR}
    ,raw_response           = CAST(#{rawResponse,jdbcType=VARCHAR} AS JSONB)
    ,pg_response_code       = #{pgResponseCode,jdbcType=VARCHAR}
    ,pg_response_message    = #{pgResponseMessage,jdbcType=VARCHAR}
    ,verified_at            = #{verifiedAt,jdbcType=TIMESTAMP}
    ,webhook_received_at    = COALESCE(#{webhookReceivedAt,jdbcType=TIMESTAMP}, now())
    ,settle_amount          = COALESCE(#{settleAmount,jdbcType=NUMERIC}, settle_amount)
    ,settle_currency        = COALESCE(NULLIF(#{settleCurrency,jdbcType=VARCHAR}, ''), settle_currency)
    ,fx_rate                = COALESCE(#{fxRate,jdbcType=NUMERIC}, fx_rate)
    ,approval_no            = NULLIF(#{approvalNo,jdbcType=VARCHAR}, '')
    ,installment_months     = COALESCE(#{installmentMonths,jdbcType=INTEGER}, installment_months)
    ,event_seq              = #{eventSeq}
    ,event_participant_seq  = #{eventParticipantSeq}
    ,participant_seq        = #{participantSeq}
    ,payer_name             = #{payerName}
    ,payer_email            = #{payerEmail}
    ,payer_country          = #{payerCountry,jdbcType=VARCHAR}
    ,event_pricing_seq      = #{eventPricingSeq}
    ,original_amount        = #{originalAmount}
    ,discount_code_seq      = #{discountCodeSeq,jdbcType=BIGINT}
    ,discount_amount        = COALESCE(#{discountAmount,jdbcType=NUMERIC}, 0)
    ,refunded_amount        = COALESCE(#{refundedAmount,jdbcType=NUMERIC}, 0)
    ,updated_by             = #{updatedBy,jdbcType=BIGINT}
    ,updated_at             = now()
WHERE payment_seq = #{paymentSeq}

UPDATE event.payments
SET  pg_transaction_id      = COALESCE(NULLIF(#{pgTransactionId,jdbcType=VARCHAR}, ''), pg_transaction_id)
    ,amount                 = COALESCE(#{amount,jdbcType=NUMERIC}, amount)
    ,currency               = COALESCE(NULLIF(#{currency,jdbcType=VARCHAR}, ''), currency)
    ,payment_method         = COALESCE(NULLIF(#{paymentMethod,jdbcType=VARCHAR}, ''), payment_method)
    ,card_company           = NULLIF(#{cardCompany,jdbcType=VARCHAR}, '')
    ,card_last4             = NULLIF(#{cardLast4,jdbcType=VARCHAR}, '')
    ,status                 = #{status}
    ,paid_at                = CASE WHEN #{paidAt,jdbcType=TIMESTAMP} IS NULL THEN paid_at ELSE #{paidAt,jdbcType=TIMESTAMP} END
    ,failed_reason          = #{failedReason,jdbcType=VARCHAR}
    ,receipt_url            = #{receiptUrl,jdbcType=VARCHAR}
    ,raw_response           = CAST(#{rawResponse,jdbcType=VARCHAR} AS JSONB)
    ,pg_response_code       = #{pgResponseCode,jdbcType=VARCHAR}
    ,pg_response_message    = #{pgResponseMessage,jdbcType=VARCHAR}
    ,verified_at            = #{verifiedAt,jdbcType=TIMESTAMP}
    ,webhook_received_at    = COALESCE(#{webhookReceivedAt,jdbcType=TIMESTAMP}, now())
    ,settle_amount          = COALESCE(#{settleAmount,jdbcType=NUMERIC}, settle_amount)
    ,settle_currency        = COALESCE(NULLIF(#{settleCurrency,jdbcType=VARCHAR}, ''), settle_currency)
    ,fx_rate                = COALESCE(#{fxRate,jdbcType=NUMERIC}, fx_rate)
    ,approval_no            = NULLIF(#{approvalNo,jdbcType=VARCHAR}, '')
    ,installment_months     = COALESCE(#{installmentMonths,jdbcType=INTEGER}, installment_months)
    ,updated_by             = #{updatedBy,jdbcType=BIGINT}
    ,updated_at             = now()
WHERE pg_order_id = #{pgOrderId}
